// Interface - object shapes, extendable
interface User {
  id: number;
  name: string;
}
interface Admin extends User {
  permissions: string[];
}

// Declaration merging (interfaces only)
interface User {
  email: string; // merged into User
}
// User now has: id, name, email

// Type alias - any type, no merging
type ID = string | number; // union - interfaces can't do this
type Point = [number, number]; // tuple
type Handler = (e: Event) => void; // function
type Nullable<T> = T | null; // generic utility

// Discriminated union (tagged union)
type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'rectangle'; width: number; height: number }
  | { kind: 'triangle'; base: number; height: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':
      return Math.PI * shape.radius  2;
    case 'rectangle':
      return shape.width * shape.height;
    case 'triangle':
      return (shape.base * shape.height) / 2;
  }
}

// TypeScript narrows the type in each case branch
// shape.radius is only accessible in 'circle' case

type HasName = { name: string };
type HasAge = { age: number };
type HasEmail = { email: string };

// Intersection: must have ALL properties
type Person = HasName & HasAge & HasEmail;

const person: Person = {
  name: 'Alice',
  age: 30,
  email: 'alice@example.com',
};

// Useful for mixins
function withTimestamp<T>(obj: T): T & { createdAt: Date } {
  return { ...obj, createdAt: new Date() };
}

const user = withTimestamp({ name: 'Bob', role: 'admin' });
// type: { name: string; role: string; createdAt: Date }

// Without generics - loses type info
function firstBad(arr: any[]): any {
  return arr[0];
}
const x = firstBad([1, 2, 3]); // type: any

// With generics - preserves type
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}
const a = first([1, 2, 3]);       // type: number
const b = first(['a', 'b']);       // type: string
const c = first<boolean>([true]);  // type: boolean

// Constrained generic
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}
const user = { name: 'Alice', age: 30 };
getProperty(user, 'name');  // OK, returns string
// getProperty(user, 'foo'); // Error: 'foo' not in keyof user

interface User {
  id: number;
  name: string;
  email: string;
  age: number;
}

// Partial<T> - all properties optional
type UpdateUser = Partial<User>;
// { id?: number; name?: string; email?: string; age?: number; }

// Pick<T, K> - select specific properties
type UserPreview = Pick<User, 'id' | 'name'>;
// { id: number; name: string; }

// Omit<T, K> - exclude properties
type CreateUser = Omit<User, 'id'>;
// { name: string; email: string; age: number; }

// Record<K, V> - create object type from keys & values
type UserRoles = Record<string, 'admin' | 'user' | 'guest'>;
// { [key: string]: 'admin' | 'user' | 'guest' }

// Readonly<T> - all properties readonly
type FrozenUser = Readonly<User>;
// All props are readonly

// Generic API response wrapper
type ApiResponse<T> = {
  data: T;
  status: number;
  message: string;
  timestamp: Date;
};

type PaginatedResponse<T> = ApiResponse<T[]> & {
  pagination: {
    page: number;
    totalPages: number;
    totalItems: number;
  };
};

// Usage
async function fetchUsers(): Promise<PaginatedResponse<User>> {
  const res = await fetch('/api/users');
  return res.json();
}

// The consumer gets full type safety
const response = await fetchUsers();
response.data[0].name;          // OK: string
response.pagination.totalPages;  // OK: number

function process(value: string | number | null) {
  // typeof narrowing
  if (typeof value === 'string') {
    console.log(value.toUpperCase()); // OK: string
  } else if (typeof value === 'number') {
    console.log(value.toFixed(2)); // OK: number
  } else {
    console.log(value); // OK: null
  }
}

// instanceof narrowing
function handleError(err: Error | string) {
  if (err instanceof Error) {
    console.log(err.message); // OK: Error
    console.log(err.stack);   // OK: Error
  } else {
    console.log(err.toUpperCase()); // OK: string
  }
}

// 'in' operator
type Dog = { bark(): void };
type Cat = { meow(): void };
function speak(pet: Dog | Cat) {
  if ('bark' in pet) {
    pet.bark(); // OK: Dog
  } else {
    pet.meow(); // OK: Cat
  }
}

interface Fish { swim(): void; name: string }
interface Bird { fly(): void; name: string }

// Custom type guard with 'is' return type
function isFish(pet: Fish | Bird): pet is Fish {
  return (pet as Fish).swim !== undefined;
}

function move(pet: Fish | Bird) {
  if (isFish(pet)) {
    pet.swim(); // OK: narrowed to Fish
  } else {
    pet.fly();  // OK: narrowed to Bird
  }
}

// Assertion function (throws if not valid)
function assertIsString(val: unknown): asserts val is string {
  if (typeof val !== 'string') {
    throw new Error(`Expected string, got ${typeof val}`);
  }
}

function greet(name: unknown) {
  assertIsString(name);
  console.log(name.toUpperCase()); // OK: narrowed to string
}

type Shape = 
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; side: number }
  | { kind: 'triangle'; base: number; height: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':
      return Math.PI * shape.radius  2;
    case 'square':
      return shape.side  2;
    case 'triangle':
      return (shape.base * shape.height) / 2;
    default:
      // Exhaustive check - if we add a new shape
      // and forget to handle it, this line errors
      const _exhaustive: never = shape;
      return _exhaustive;
  }
}

